 #include<bits/stdc++.h>
using namespace std;

int w[100001],v[100001],dp[1000001],n,m;

int main(){
    cin>>m>>n;
    for(int i=1;i<=n;i++){
        cin>>v[i]>>w[i];
    }for(int i=1;i<=n;i++){
        for(int j=w[i];j<=m;j++){
            dp[j]=max(dp[j],dp[j-w[i]]+v[i]);
        }
    }cout<<dp[m];
}
